const aiItems = $('Analyze image').all();
const imageItems = $('Output multiple images into 1  names1').all();

function cleanCaption(text) {
  return text
    // remove "Caption:" or similar headings
    .replace(/#?\s*🤖?\s*caption:\s*/i, '')

    // remove "Hashtags" section completely
    .replace(/---[\s\S]*$/i, '')

    // remove markdown (**, ##, etc.)
    .replace(/[*#_`]/g, '')

    // remove quotes at start/end
    .replace(/^"+|"+$/g, '')

    // trim extra spaces/newlines
    .trim();
}

return aiItems.map((aiItem, index) => {
  const raw =
    aiItem.json.text ||
    aiItem.json.content?.[0]?.text ||
    '';

  const cleaned = cleanCaption(raw);

  return {
    json: {
      ...imageItems[index].json,
      caption: cleaned
    },
    ...(imageItems[index].binary && {
      binary: imageItems[index].binary
    })
  };
});

